@dataclass
class Dependency:
    """Represents a single dependency with its metadata."""
    name: str
    version: str
    hashes: List[str] = field(default_factory=list)
    is_dev: bool = False
    extras: List[str] = field(default_factory=list)
    markers: Optional[str] = None
    source: Optional[str] = None

    @property
    def pinned_spec(self) -> str:
        extras_str = f"[{','.join(self.extras)}]" if self.extras else ""
        marker_str = f" ; {self.markers}" if self.markers else ""
        return f"{self.name}{extras_str}=={self.version}{marker_str}"

    @property
    def pinned_spec_with_hashes(self) -> str:
        base = self.pinned_spec
        if self.hashes:
            hash_lines = " \\\n".join(f"    --hash={h}" for h in self.hashes)
            return f"{base} \\\n{hash_lines}"
        return base


@dataclass
class LockFileMetadata:
    """Metadata stored alongside a lock file."""
    generated_at: str
    python_version: str
    platform: str
    backend: str
    pip_compile_version: Optional[str] = None
    poetry_version: Optional[str] = None
    content_hash: Optional[str] = None


@dataclass
class DependencyManifest:
    """Complete dependency manifest for the project."""
    production: List[Dependency] = field(default_factory=list)
    development: List[Dependency] = field(default_factory=list)
    metadata: Optional[LockFileMetadata] = None

    @property
    def all_dependencies(self) -> List[Dependency]:
        return self.production + self.development

    def find(self, name: str) -> Optional[Dependency]:
        normalized = self._normalize(name)
        for dep in self.all_dependencies:
            if self._normalize(dep.name) == normalized:
                return dep
        return None

    @staticmethod
    def _normalize(name: str) -> str:
        return re.sub(r"[-_.]+", "-", name).lower()


