def run_command(
    cmd: List[str],
    capture: bool = True,
    check: bool = True,
    cwd: Optional[Path] = None,
) -> subprocess.CompletedProcess:
    """Run a shell command with logging."""
    logger.debug("Running: %s", " ".join(cmd))
    try:
        result = subprocess.run(
            cmd,
            capture_output=capture,
            text=True,
            check=check,
            cwd=cwd or PROJECT_ROOT,
        )
        return result
    except FileNotFoundError:
        logger.error("Command not found: %s", cmd[0])
        logger.error(
            "Please install the required tool. See setup instructions below."
        )
        raise
    except subprocess.CalledProcessError as exc:
        logger.error("Command failed (exit %d): %s", exc.returncode, " ".join(cmd))
        if exc.stderr:
            logger.error("stderr:\n%s", exc.stderr)
        raise


def compute_file_hash(path: Path, algorithm: str = "sha256") -> str:
    """Compute a hex-digest hash of a file."""
    h = hashlib.new(algorithm)
    with open(path, "rb") as fh:
        for chunk in iter(lambda: fh.read(8192), b""):
            h.update(chunk)
    return f"{algorithm}:{h.hexdigest()}"


def tool_available(name: str) -> bool:
    """Check whether a CLI tool is available on PATH."""
    return shutil.which(name) is not None


def detect_backend() -> Backend:
    """Auto-detect which backend the project is using."""
    if (PROJECT_ROOT / POETRY_PYPROJECT).exists():
        # Check whether it actually uses Poetry
        content = (PROJECT_ROOT / POETRY_PYPROJECT).read_text()
        if "[tool.poetry]" in content:
            return Backend.POETRY
    if (PROJECT_ROOT / PIP_REQUIREMENTS_IN).exists():
        return Backend.PIP
    if (PROJECT_ROOT / PIP_REQUIREMENTS_TXT).exists():
        return Backend.PIP
    # Default to pip
    return Backend.PIP


def current_metadata(backend: Backend) -> LockFileMetadata:
    """Generate metadata for the current environment."""
    pip_compile_ver = None
    poetry_ver = None
    if backend == Backend.PIP and tool_available("pip-compile"):
        try:
            r = run_command(["pip-compile", "--version"])
            pip_compile_ver = r.stdout.strip()
        except Exception:
            pass
    if backend == Backend.POETRY and tool_available("poetry"):
        try:
            r = run_command(["poetry", "--version"])
            poetry_ver = r.stdout.strip()
        except Exception:
            pass

    return LockFileMetadata(
        generated_at=datetime.utcnow().isoformat() + "Z",
        python_version=f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}",
        platform=sys.platform,
        backend=backend.value,
        pip_compile_version=pip_compile_ver,
        poetry_version=poetry_ver,
    )


