class PipBackend:
    """
    Manages dependencies using pip-compile (from pip-tools) to produce
    fully pinned requirements.txt files **with hashes**.

    Workflow
    --------
    1. Declare *abstract* dependencies in ``requirements.in`` (production)
       and ``requirements-dev.in`` (development / testing).
    2. Run ``pip-compile`` to resolve versions and generate lock files
       (``requirements.txt`` / ``requirements-dev.txt``) including hashes.
    3. Install with ``pip install -r requirements.txt`` (or dev variant).

    Files
    -----
    * ``requirements.in``       – unpinned production deps (committed)
    * ``requirements-dev.in``   – unpinned dev deps (committed)
    * ``requirements.txt``      – locked production deps w/ hashes (committed)
    * ``requirements-dev.txt``  – locked dev deps w/ hashes (committed)
    """

    def __init__(self, root: Path = PROJECT_ROOT):
        self.root = root

    # -- Bootstrapping -------------------------------------------------------

    def init(self) -> None:
        """Create starter requirement input files if they don't exist."""
        self._ensure_pip_tools()

        prod_in = self.root / PIP_REQUIREMENTS_IN
        dev_in = self.root / PIP_REQUIREMENTS_DEV_IN

        if not prod_in.exists():
            prod_in.write_text(
                "# Production dependencies – add packages here.\n"
                "# Run `python dependency_manager.py lock` to resolve.\n"
                "#\n"
                "# Examples:\n"
                "# requests>=2.28\n"
                "# sqlalchemy>=2.0,<3\n"
            )
            logger.info("Created %s", prod_in)

        if not dev_in.exists():
            dev_in.write_text(
                "# Development / test dependencies.\n"
                "# These extend production deps.\n"
                f"-r {PIP_REQUIREMENTS_IN}\n"
                "#\n"
                "# Examples:\n"
                "# pytest>=7\n"
                "# mypy\n"
                "# ruff\n"
            )
            logger.info("Created %s", dev_in)

        logger.info(
            "Pip backend initialised. Edit the .in files then run 'lock'."
        )

    # -- Locking -------------------------------------------------------------

    def lock(self) -> None:
        """
        Resolve and lock all dependencies with hashes.

        This runs pip-compile for both production and development input files,
        producing fully pinned lock files with --generate-hashes.
        """
        self._ensure_pip_tools()
        meta = current_metadata(Backend.PIP)

        # Production
        prod_in = self.root / PIP_REQUIREMENTS_IN
        prod_out = self.root / PIP_REQUIREMENTS_TXT
        if prod_in.exists():
            self._compile(prod_in, prod_out)
            self._prepend_metadata(prod_out, meta)
            logger.info("Locked production dependencies → %s", prod_out.name)
        else:
            logger.warning("%s not found – skipping production lock.", prod_in.name)

        # Development
        dev_in = self.root / PIP_REQUIREMENTS_DEV_IN
        dev_out = self.root / PIP_REQUIREMENTS_DEV_TXT
        if dev_in.exists():
            self._compile(dev_in, dev_out)
            self._prepend_metadata(dev_out, meta)
            logger.info("Locked development dependencies → %s", dev_out.name)
        else:
            logger.warning("%s not found – skipping dev lock.", dev_in.name)

    def _compile(self, input_file: Path, output_file: Path) -> None:
        """Run pip-compile with hashes."""
        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--generate-hashes",
            "--no-header",
            "--allow-unsafe",          # pin setuptools / pip if needed
            "--resolver=backtracking",
            "--strip-extras",
            "--output-file", str(output_file),
            str(input_file),
        ]
        run_command(cmd, cwd=self.root)

    # -- Updating ------------------------------------------------------------

    def update(self, package: Optional[str] = None) -> None:
        """
        Update one or all packages then re-lock.

        Parameters
        ----------
        package : str or None
            If given, only that package is upgraded.
        """
        self._ensure_pip_tools()

        upgrade_flag = (
            ["--upgrade-package", package] if package else ["--upgrade"]
        )

        for in_file_name, out_file_name in [
            (PIP_REQUIREMENTS_IN, PIP_REQUIREMENTS_TXT),
            (PIP_REQUIREMENTS_DEV_IN, PIP_REQUIREMENTS_DEV_TXT),
        ]:
            in_file = self.root / in_file_name
            out_file = self.root / out_file_name
            if not in_file.exists():
                continue
            cmd = [
                sys.executable, "-m", "piptools", "compile",
                "--generate-hashes",
                "--no-header",
                "--allow-unsafe",
                "--resolver=backtracking",
                "--strip-extras",
                "--output-file", str(out_file),
                *upgrade_flag,
                str(in_file),
            ]
            run_command(cmd, cwd=self.root)
            self._prepend_metadata(out_file, current_metadata(Backend.PIP))
            target = package or "all packages"
            logger.info("Updated %s in %s", target, out_file.name)

    # -- Syncing (install) ---------------------------------------------------

    def sync(self, env: Environment = Environment.ALL) -> None:
        """
        Install exactly the locked dependencies into the current virtualenv.

        Uses pip-sync to ensure the environment matches the lock file exactly
        (removing packages that are not in the lock file).
        """
        self._ensure_pip_tools()
        files: List[str] = []

        if env in (Environment.PROD, Environment.ALL):
            prod = self.root / PIP_REQUIREMENTS_TXT
            if prod.exists():
                files.append(str(prod))

        if env in (Environment.DEV, Environment.ALL):
            dev = self.root / PIP_REQUIREMENTS_DEV_TXT
            if dev.exists():
                files.append(str(dev))

        if not files:
            logger.error("No lock files found. Run 'lock' first.")
            return

        cmd = [sys.executable, "-m", "piptools", "sync", *files]
        run_command(cmd, capture=False, cwd=self.root)
        logger.info("Environment synchronised with: %s", ", ".join(files))

    # -- Adding / Removing ---------------------------------------------------

    def add(self, package: str, dev: bool = False) -> None:
        """Add a package to the appropriate .in file and re-lock."""
        target = (
            self.root / (PIP_REQUIREMENTS_DEV_IN if dev else PIP_REQUIREMENTS_IN)
        )
        if not target.exists():
            logger.error("%s not found. Run 'init' first.", target.name)
            return

        # Avoid duplicates (case-insensitive, normalised)
        existing = target.read_text()
        normalised = re.sub(r"[-_.]+", "-", package.split("[")[0].split(">")[0].split("<")[0].split("=")[0].split("!")[0]).lower()
        for line in existing.splitlines():
            stripped = line.strip()
            if stripped.startswith("#") or stripped.startswith("-"):
                continue
            line_pkg = re.sub(r"[-_.]+", "-", stripped.split("[")[0].split(">")[0].split("<")[0].split("=")[0].split("!")[0]).lower()
            if line_pkg == normalised:
                logger.warning("'%s' already present in %s", package, target.name)
                return

        with open(target, "a") as fh:
            fh.write(f"{package}\n")
        logger.info("Added '%s' to %s", package, target.name)
        self.lock()

    def remove(self, package: str) -> None:
        """Remove a package from all .in files and re-lock."""
        normalised = re.sub(r"[-_.]+", "-", package).lower()
        removed = False
        for fname in (PIP_REQUIREMENTS_IN, PIP_REQUIREMENTS_DEV_IN):
            fpath = self.root / fname
            if not fpath.exists():
                continue
            lines = fpath.read_text().splitlines()
            new_lines = []
            for line in lines:
                stripped = line.strip()
                if stripped.startswith("#") or stripped.startswith("-") or not stripped:
                    new_lines.append(line)
                    continue
                line_pkg = re.sub(
                    r"[-_.]+", "-",
                    stripped.split("[")[0].split(">")[0].split("<")[0].split("=")[0].split("!")[0],
                ).lower()
                if line_pkg == normalised:
                    removed = True
                    logger.info("Removed '%s' from %s", package, fname)
                    continue
                new_lines.append(line)
            fpath.write_text("\n".join(new_lines) + "\n")

        if removed:
            self.lock()
        else:
            logger.warning("'%s' not found in any .in file.", package)

    # -- Verification --------------------------------------------------------

    def verify(self) -> bool:
        """
        Verify that the lock file is consistent with the input file.
        Returns True if the lock is up-to-date.
        """
        self._ensure_pip_tools()
        all_ok = True
        for in_name, out_name in [
            (PIP_REQUIREMENTS_IN, PIP_REQUIREMENTS_TXT),
            (PIP_REQUIREMENTS_DEV_IN, PIP_REQUIREMENTS_DEV_TXT),
        ]:
            in_path = self.root / in_name
            out_path = self.root / out_name
            if not in_path.exists():
                continue

            with tempfile.NamedTemporaryFile(suffix=".txt", delete=False) as tmp:
                tmp_path = Path(tmp.name)

            try:
                cmd = [
                    sys.executable, "-m", "piptools", "compile",
                    "--generate-hashes",
                    "--no-header",
                    "--allow-unsafe",
                    "--resolver=backtracking",
                    "--strip-extras",
                    "--output-file", str(tmp_path),
                    str(in_path),
                ]
                run_command(cmd, cwd=self.root)
                # Compare ignoring metadata header
                current = self._strip_metadata(out_path.read_text()) if out_path.exists() else ""
                fresh = tmp_path.read_text()
                if current.strip() != fresh.strip():
                    logger.warning(
                        "MISMATCH: %s is out of date with respect to %s",
                        out_name,
                        in_name,
                    )
                    all_ok = False
                else:
                    logger.info("OK: %s is up to date.", out_name)
            finally:
                tmp_path.unlink(missing_ok=True)

        return all_ok

    # -- Auditing ------------------------------------------------------------

    def audit(self) -> None:
        """
        Run security audit on locked dependencies using pip-audit.
        """
        if not tool_available("pip-audit"):
            logger.error(
                "pip-audit not found. Install it: pip install pip-audit"
            )
            return

        for lock_file in (PIP_REQUIREMENTS_TXT, PIP_REQUIREMENTS_DEV_TXT):
            path = self.root / lock_file
            if not path.exists():
                continue
            logger.info("Auditing %s …", lock_file)
            try:
                run_command(
                    ["pip-audit", "-r", str(path), "--desc", "on"],
                    capture=False,
                    cwd=self.root,
                )
                logger.info("No vulnerabilities found in %s.", lock_file)
            except subprocess.CalledProcessError:
                logger.error("Vulnerabilities detected in %s!", lock_file)

    # -- Export --------------------------------------------------------------

    def export(self) -> str:
        """Return the contents of the production lock file."""
        path = self.root / PIP_REQUIREMENTS_TXT
        if not path.exists():
            return ""
        return path.read_text()

    # -- Helpers -------------------------------------------------------------

    @staticmethod
    def _ensure_pip_tools() -> None:
        """Make sure pip-tools is installed."""
        try:
            import piptools  # noqa: F401
        except ImportError:
            logger.info("Installing pip-tools …")
            run_command(
                [sys.executable, "-m", "pip", "install", "pip-tools"],
                capture=False,
            )

    @staticmethod
    def _prepend_metadata(path: Path, meta: LockFileMetadata) -> None:
        """Prepend metadata comment block to a lock file."""
        content = path.read_text()
        header = (
            f"{LOCK_METADATA_HEADER}\n"
            f"# generated_at: {meta.generated_at}\n"
            f"# python_version: {meta.python_version}\n"
            f"# platform: {meta.platform}\n"
            f"# backend: {meta.backend}\n"
        )
        if meta.pip_compile_version:
            header += f"# pip_compile_version: {meta.pip_compile_version}\n"
        header += f"# content_hash: {compute_file_hash(path)}\n"
        header += "#\n"
        path.write_text(header + content)

    @staticmethod
    def _strip_metadata(text: str) -> str:
        """Remove our metadata header from lock file text for comparison."""
        lines = text.splitlines()
        result = []
        in_header = False
        for line in lines:
            if line.strip() == LOCK_METADATA_HEADER:
                in_header = True
                continue
            if in_header:
                if line.startswith("#"):
                    continue
                in_header = False
            result.append(line)
        return "\n".join(result)


