class PoetryBackend:
    """
    Manages dependencies via Poetry and ``pyproject.toml``.

    Workflow
    --------
    1. Declare dependencies in ``[tool.poetry.dependencies]`` and
       ``[tool.poetry.group.dev.dependencies]`` inside ``pyproject.toml``.
    2. Run ``poetry lock`` to resolve and write ``poetry.lock``.
    3. Install with ``poetry install`` (all groups) or
       ``poetry install --only main`` (production only).

    Files
    -----
    * ``pyproject.toml`` – project metadata & dependency declarations (committed)
    * ``poetry.lock``    – resolved dependency tree with hashes (committed)
    """

    def __init__(self, root: Path = PROJECT_ROOT):
        self.root = root

    def _poetry(self, args: List[str], **kwargs) -> subprocess.CompletedProcess:
        return run_command(["poetry", *args], cwd=self.root, **kwargs)

    # -- Bootstrapping -------------------------------------------------------

    def init(self) -> None:
        """Initialise a new Poetry project if pyproject.toml doesn't exist."""
        self._ensure_poetry()
        if not (self.root / POETRY_PYPROJECT).exists():
            self._poetry(["init", "--no-interaction"], capture=False)
            logger.info("Created %s via Poetry.", POETRY_PYPROJECT)
        else:
            logger.info("%s already exists.", POETRY_PYPROJECT)

    # -- Locking -------------------------------------------------------------

    def lock(self) -> None:
        """
        Resolve dependencies and write poetry.lock.

        Equivalent to ``poetry lock --no-update`` but we use ``poetry lock``
        so the full resolution runs.
        """
        self._ensure_poetry()
        self._poetry(["lock"], capture=False)
        logger.info("Dependencies locked in %s.", POETRY_LOCK)

    # -- Updating ------------------------------------------------------------

    def update(self, package: Optional[str] = None) -> None:
        """Update one or all packages."""
        self._ensure_poetry()
        cmd = ["update"]
        if package:
            cmd.append(package)
        self._poetry(cmd, capture=False)
        target = package or "all packages"
        logger.info("Updated %s.", target)

    # -- Syncing (install) ---------------------------------------------------

    def sync(self, env: Environment = Environment.ALL) -> None:
        """Install dependencies from the lock file."""
        self._ensure_poetry()
        cmd = ["install"]
        if env == Environment.PROD:
            cmd.extend(["--only", "main"])
        elif env == Environment.DEV:
            cmd.extend(["--with", "dev"])
        # ALL installs everything (default behaviour)
        self._poetry(cmd, capture=False)
        logger.info("Environment synchronised (env=%s).", env.value)

    # -- Adding / Removing ---------------------------------------------------

    def add(self, package: str, dev: bool = False) -> None:
        """Add a package via poetry add."""
        self._ensure_poetry()
        cmd = ["add"]
        if dev:
            cmd.append("--group=dev")
        cmd.append(package)
        self._poetry(cmd, capture=False)
        logger.info("Added '%s' (dev=%s).", package, dev)

    def remove(self, package: str) -> None:
        """Remove a package via poetry remove."""
        self._ensure_poetry()
        # Try main first, then dev group
        try:
            self._poetry(["remove", package], capture=False)
        except subprocess.CalledProcessError:
            try:
                self._poetry(["remove", "--group=dev", package], capture=False)
            except subprocess.CalledProcessError:
                logger.error("Could not remove '%s'.", package)
                return
        logger.info("Removed '%s'.", package)

    # -- Verification --------------------------------------------------------

    def verify(self) -> bool:
        """Check that poetry.lock is consistent with pyproject.toml."""
        self._ensure_poetry()
        try:
            result = self._poetry(["check", "--lock"])
            logger.info("Lock file is valid.")
            return True
        except subprocess.CalledProcessError:
            logger.warning("Lock file is NOT consistent with pyproject.toml.")
            return False

    # -- Auditing ------------------------------------------------------------

    def audit(self) -> None:
        """Audit dependencies for vulnerabilities."""
        # Option 1: poetry-audit-plugin
        # Option 2: export to requirements.txt then use pip-audit
        self._ensure_poetry()
        logger.info("Exporting to temporary requirements.txt for audit …")
        with tempfile.NamedTemporaryFile(
            suffix=".txt", delete=False, mode="w"
        ) as tmp:
            tmp_path = Path(tmp.name)

        try:
            self._poetry(
                [
                    "export",
                    "--format=requirements.txt",
                    "--without-hashes",
                    "--output",
                    str(tmp_path),
                ]
            )
            if tool_available("pip-audit"):
                run_command(
                    ["pip-audit", "-r", str(tmp_path), "--desc", "on"],
                    capture=False,
                )
                logger.info("No vulnerabilities found.")
            else:
                logger.error(
                    "pip-audit not found. Install: pip install pip-audit"
                )
        except subprocess.CalledProcessError:
            logger.error("Vulnerabilities detected or audit failed!")
        finally:
            tmp_path.unlink(missing_ok=True)

    # -- Export --------------------------------------------------------------

    def export(self) -> str:
        """Export locked deps as requirements.txt (with hashes)."""
        self._ensure_poetry()
        result = self._poetry(
            ["export", "--format=requirements.txt", "--with-credentials"]
        )
        return result.stdout

    # -- Helpers -------------------------------------------------------------

    @staticmethod
    def _ensure_poetry() -> None:
        if not tool_available("poetry"):
            logger.error(
                "Poetry is not installed.\n"
                "Install: https://python-poetry.org/docs/#installation\n"
                "  curl -sSL https://install.python-poetry.org | python3 -"
            )
            sys.exit(1)


