# ---------------------------------------------------------------------------


class DependencyManager:
    """
    Unified facade that delegates to the appropriate backend.

    This class is the main entry point for all dependency management
    operations. It auto-detects (or accepts) the backend and provides
    a consistent API.
    """

    def __init__(self, backend: Optional[Backend] = None, root: Path = PROJECT_ROOT):
        self.root = root
        self.backend_type = backend or detect_backend()
        if self.backend_type == Backend.PIP:
            self._backend = PipBackend(root)
        else:
            self._backend = PoetryBackend(root)
        logger.info("Using backend: %s", self.backend_type.value)

    def init(self) -> None:
        """
        Initialise the project for dependency management.

        For pip: creates requirements.in and requirements-dev.in
        For poetry: creates pyproject.toml via ``poetry init``
        """
        self._backend.init()

    def lock(self) -> None:
        """
        Resolve and lock all dependencies.

        This creates deterministic lock files that should be committed
        to version control. All team members and CI/CD pipelines should
        use these lock files to install dependencies.
        """
        self._backend.lock()

    def update(self, package: Optional[str] = None) -> None:
        """
        Update dependencies and regenerate the lock file.

        Parameters
        ----------
        package : str, optional
            Update only this package. If None, updates everything.
        """
        self._backend.update(package)

    def sync(self, env: Environment = Environment.ALL) -> None:
        """
        Install the exact locked dependencies into the current environment.

        Parameters
        ----------
        env : Environment
            Which dependency group to install.
            - PROD: only production dependencies
            - DEV: development dependencies (usually includes prod)
            - ALL: everything
        """
        self._backend.sync(env)

    def add(self, package: str, dev: bool = False) -> None:
        """
        Add a new dependency and re-lock.

        Parameters
        ----------
        package : str
            Package specifier, e.g. "requests>=2.28" or "flask"
        dev : bool
            Whether this is a development-only dependency
        """
        self._backend.add(package, dev)

    def remove(self, package: str) -> None:
        """Remove a dependency and re-lock."""
        self._backend.remove(package)

    def verify(self) -> bool:
        """
        Verify the lock file is consistent with the input declarations.

        Returns True if everything is in sync, False otherwise.
        Useful as a CI/CD check to ensure developers committed their
        lock file changes.
        """
        return self._backend.verify()

    def audit(self) -> None:
        """
        Run a security vulnerability audit against locked dependencies.

        Uses pip-audit under the hood. Install it with:
            pip install pip-audit
        """
        self._backend.audit()

    def export(self) -> str:
        """
        Export locked dependencies as a requirements.txt string.

        Useful for Docker builds or environments that only support pip.
        """
        return self._backend.export()

    def status(self) -> None:
        """Print a summary of the current dependency configuration."""
        print("=" * 60)
        print("Dependency Management Status")
        print("=" * 60)
        print(f"Backend       : {self.backend_type.value}")
        print(f"Project root  : {self.root}")
        print(f"Python        : {sys.version}")
        print()

        if self.backend_type == Backend.PIP:
            files = [
                PIP_REQUIREMENTS_IN,
                PIP_REQUIREMENTS_DEV_IN,
                PIP_REQUIREMENTS_TXT,
                PIP_REQUIREMENTS_DEV_TXT,
            ]
        else:
            files = [POETRY_PYPROJECT, POETRY_LOCK]

        for f in files:
            path = self.root / f
            if path.exists():
                size = path.stat().st_size
                mtime = datetime.fromtimestamp(path.stat().st_mtime).isoformat()
                print(f"  ✓ {f:30s}  {size:>8,} bytes  (modified {mtime})")
            else:
                print(f"  ✗ {f:30s}  MISSING")
        print()

        # Count locked packages
        if self.backend_type == Backend.PIP:
            lock_path = self.root / PIP_REQUIREMENTS_TXT
            if lock_path.exists():
                count = sum(
                    1
                    for line in lock_path.read_text().splitlines()
                    if line.strip()
                    and not line.strip().startswith("#")
                    and not line.strip().startswith("-")
                    and not line.strip().startswith("\\")
                    and "==" in line
                )
                print(f"  Locked production packages: {count}")
        else:
            lock_path = self.root / POETRY_LOCK
            if lock_path.exists():
                count = lock_path.read_text().count("[[package]]")
                print(f"  Locked packages: {count}")

        print("=" * 60)


# ---------------------------------------------------------------------------
# CI/CD Helper Functions
# ---------------------------------------------------------------------------


def ci_verify_lockfile(backend: Optional[str] = None) -> int:
    """
    CI/CD entry point: verify the lock file is up to date.

    Returns 0 on success, 1 on failure (suitable as a process exit code).

    Usage in CI:
        python dependency_manager.py verify
    """
    b = Backend(backend) if backend else None
    manager = DependencyManager(backend=b)
    if manager.verify():
        print("✓ Lock file is up to date.")
        return 0
    else:
        print("✗ Lock file is out of date. Run 'python dependency_manager.py lock'.")
        return 1


def ci_install_production() -> int:
    """
    CI/CD entry point: install only production dependencies.

    Usage in Dockerfile:
        RUN python dependency_manager.py sync --env prod
    """
    manager = DependencyManager()
    manager.sync(Environment.PROD)
    return 0


# ---------------------------------------------------------------------------
# Dockerfile / CI Configuration Generators
# ---------------------------------------------------------------------------


def generate_dockerfile_snippet(backend: Backend) -> str:
    """
    Generate a Dockerfile snippet that leverages the lock file
    for reproducible builds.
    """
    if backend == Backend.PIP:
        return '''\
# === Multi-stage build with locked Python dependencies ===

# Stage 1: Install dependencies
FROM python:3.12-slim AS builder

WORKDIR /app

# Copy only lock files first (for layer caching)
COPY requirements.txt ./

# Install with --require-hashes for supply-chain security
RUN pip install --no-cache-dir --require-hashes -r requirements.txt

# Stage 2: Runtime
FROM python:3.12-slim AS runtime

WORKDIR /app

# Copy installed packages from builder
COPY --from=builder /usr/local/lib/python3.12/site-packages /usr/local/lib/python3.12/site-packages
COPY --from=builder /usr/local/bin /usr/local/bin

# Copy application code
COPY . .

CMD ["python", "-m", "myapp"]
'''
    else:
        return '''\
# === Multi-stage build with Poetry lock file ===

# Stage 1: Install dependencies
FROM python:3.12-slim AS builder

RUN pip install poetry==1.8.2
ENV POETRY_VIRTUALENVS_IN_PROJECT=true

WORKDIR /app

# Copy only dependency files first (for layer caching)
COPY pyproject.toml poetry.lock ./

# Install production deps only (no dev)
RUN poetry install --only main --no-interaction --no-ansi

# Stage 2: Runtime
FROM python:3.12-slim AS runtime

WORKDIR /app

# Copy virtualenv from builder
COPY --from=builder /app/.venv /app/.venv
ENV PATH="/app/.venv/bin:$PATH"

# Copy application code
COPY . .

CMD ["python", "-m", "myapp"]
'''


def generate_github_actions_snippet(backend: Backend) -> str:
    """
    Generate a GitHub Actions workflow snippet for dependency management.
    """
    if backend == Backend.PIP:
        return '''\
# .github/workflows/deps.yml
name: Dependency Check

on:
  pull_request:
    paths:
      - 'requirements*.in'
      - 'requirements*.txt'
  schedule:
    # Weekly dependency audit
    - cron: '0 9 * * 1'

jobs:
  verify-lockfile:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - uses: actions/setup-python@v5
        with:
          python-version: '3.12'

      - name: Install tools
        run: pip install pip-tools pip-audit

      - name: Verify lock files are up to date
        run: python dependency_manager.py verify

      - name: Audit for vulnerabilities
        run: python dependency_manager.py audit
'''
    else:
        return '''\
# .github/workflows/deps.yml
name: Dependency Check

on:
  pull_request:
    paths:
      - 'pyproject.toml'
      - 'poetry.lock'
  schedule:
    - cron: '0 9 * * 1'

jobs:
  verify-lockfile:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - uses: actions/setup-python@v5
        with:
          python-version: '3.12'

      - name: Install Poetry
        uses: snok/install-poetry@v1
        with:
          version: 1.8.2

      - name: Verify lock file
        run: poetry check --lock

      - name: Install pip-audit
        run: pip install pip-audit

      - name: Audit for vulnerabilities
        run: python dependency_manager.py audit
'''


