def print_best_practices() -> None:
    """Print the team's dependency management best practices."""
    doc = """
╔══════════════════════════════════════════════════════════════╗
║          DEPENDENCY MANAGEMENT BEST PRACTICES               ║
╚══════════════════════════════════════════════════════════════╝

1. ALWAYS COMMIT LOCK FILES
   ─────────────────────────
   Lock files (requirements.txt or poetry.lock) MUST be committed to
   version control. They ensure every developer, CI runner, and production
   server uses identical package versions.

   ✓ Commit: requirements.txt, requirements-dev.txt (pip)
   ✓ Commit: poetry.lock (Poetry)
   ✓ Commit: requirements.in, requirements-dev.in (pip input files)
   ✓ Commit: pyproject.toml (Poetry/project config)

2. USE HASHES FOR SUPPLY-CHAIN SECURITY
   ─────────────────────────────────────
   pip-compile --generate-hashes adds SHA-256 hashes to every package.
   When installing with --require-hashes, pip verifies each download
   against these hashes, preventing tampered packages.

   Poetry includes hashes in poetry.lock by default.

3. SEPARATE DEV AND PRODUCTION DEPENDENCIES
   ─────────────────────────────────────────
   • requirements.in       → production only (requests, gunicorn, etc.)
   • requirements-dev.in   → dev + test tools (pytest, mypy, ruff, etc.)

   In production / Docker, install ONLY production deps:
     pip install --require-hashes -r requirements.txt

4. ADDING A NEW DEPENDENCY
   ────────────────────────
   pip workflow:
     1. Add to requirements.in (or requirements-dev.in)
     2. Run: python dependency_manager.py lock
     3. Commit both .in and .txt files

   Poetry workflow:
     1. Run: poetry add <package>  (or poetry add --group=dev <package>)
     2. Commit pyproject.toml and poetry.lock

5. UPDATING DEPENDENCIES
   ──────────────────────
   Update a single package:
     python dependency_manager.py update requests

   Update everything:
     python dependency_manager.py update

   After updating, always:
     • Run the full test suite
     • Review the diff in the lock file
     • Commit the changes

6. CI/CD CHECKS
   ─────────────
   Add these checks to your CI pipeline:

   a) VERIFY: Ensure lock files match input files
      python dependency_manager.py verify

   b) AUDIT: Scan for known vulnerabilities
      python dependency_manager.py audit

   c) INSTALL: Use lock files for reproducible builds
      python dependency_manager.py sync --env prod

7. REGULAR MAINTENANCE
   ────────────────────
   • Weekly: Run `python dependency_manager.py audit`
   • Monthly: Run `python dependency_manager.py update` and test
   • Use Dependabot or Renovate for automated PRs

8. VIRTUAL ENVIRONMENTS
   ─────────────────────
   Always work inside a virtual environment:
     python -m venv .venv
     source .venv/bin/activate  # Linux/macOS
     .venv\\Scripts\\activate   # Windows

   This script's 'sync' command will install into the active venv.

9. DOCKER BUILDS
   ──────────────
   Copy lock files BEFORE application code to leverage Docker layer caching.
   See: python dependency_manager.py --generate-dockerfile

10. TROUBLESHOOTING
    ───────────────
    • "Hash mismatch" → Re-run lock: python dependency_manager.py lock
    • "Resolver conflict" → Check version constraints in .in files
    • "Lock out of date" → Run lock, commit, push
"""
    print(doc)


# ---------------------------------------------------------------------------
# CLI Entry Point
# ---------------------------------------------------------------------------


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog="dependency_manager",
        description="Manage Python dependency lock files for consistent environments.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  %(prog)s init                      Initialise dependency files
  %(prog)s lock                      Resolve and lock all dependencies
  %(prog)s update                    Update all packages and re-lock
  %(prog)s update requests           Update only 'requests'
  %(prog)s sync --env prod           Install production deps exactly
  %(prog)s add flask                 Add flask to production deps
  %(prog)s add pytest --dev          Add pytest to dev deps
  %(prog)s remove flask              Remove flask
  %(prog)s verify                    Check lock file consistency (CI)
  %(prog)s audit                     Security vulnerability scan
  %(prog)s export                    Print locked deps as requirements.txt
  %(prog)s status                    Show current configuration
  %(prog)s docs                      Print best practices documentation
  %(prog)s --generate-dockerfile     Print Dockerfile snippet
  %(prog)s --generate-ci             Print GitHub Actions snippet
""",
    )

    parser.add_argument(
        "--backend",
        choices=["pip", "poetry"],
        default=None,
        help="Force a specific backend (default: auto-detect)",
    )
    parser.add_argument(
        "--root",
        type=Path,
        default=PROJECT_ROOT,
        help="Project root directory (default: current dir)",
    )
    parser.add_argument(
        "--generate-dockerfile",
        action="store_true",
        help="Print a Dockerfile snippet and exit",
    )
    parser.add_argument(
        "--generate-ci",
        action="store_true",
        help="Print a GitHub Actions CI snippet and exit",
    )
    parser.add_argument(
        "-v", "--verbose",
        action="store_true",
        help="Enable debug logging",
    )

    subparsers = parser.add_subparsers(dest="command", help="Command to run")

    # init
    subparsers.add_parser("init", help="Initialise dependency management files")

    # lock
    subparsers.add_parser("lock", help="Resolve and lock dependencies")

    # update
    update_parser = subparsers.add_parser("update", help="Update dependencies")
    update_parser.add_argument(
        "package", nargs="?", default=None, help="Package to update (all if omitted)"
    )

    # sync
    sync_parser = subparsers.add_parser("sync", help="Install locked dependencies")
    sync_parser.add_argument(
        "--env",
        choices=["dev", "prod", "all"],
        default="all",
        help="Environment to sync (default: all)",
    )

    # add
    add_parser = subparsers.add_parser("add", help="Add a dependency")
    add_parser.add_argument("package", help="Package specifier (e.g. 'requests>=2.28')")
    add_parser.add_argument("--dev", action="store_true", help="Add as dev dependency")

    # remove
    remove_parser = subparsers.add_parser("remove", help="Remove a dependency")
    remove_parser.add_argument("package", help="Package name to remove")

    # verify
    subparsers.add_parser("verify", help="Verify lock file consistency")

    # audit
    subparsers.add_parser("audit", help="Audit for security vulnerabilities")

    # export
    subparsers.add_parser("export", help="Export locked deps as requirements.txt")

    # status
    subparsers.add_parser("status", help="Show dependency management status")

    # docs
    subparsers.add_parser("docs", help="Print best practices documentation")

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    # Handle generation flags (no command needed)
    backend_hint = Backend(args.backend) if args.backend else detect_backend()

    if args.generate_dockerfile:
        print(generate_dockerfile_snippet(backend_hint))
        return 0

    if args.generate_ci:
        print(generate_github_actions_snippet(backend_hint))
        return 0

    if not args.command:
        parser.print_help()
        return 0

    # Build manager
    b = Backend(args.backend) if args.backend else None
    manager = DependencyManager(backend=b, root=args.root)

    # Dispatch commands
    if args.command == "init":
        manager.init()

    elif args.command == "lock":
        manager.lock()

    elif args.command == "update":
        manager.update(args.package)

    elif args.command == "sync":
        env_map = {"dev": Environment.DEV, "prod": Environment.PROD, "all": Environment.ALL}
        manager.sync(env_map[args.env])

    elif args.command == "add":
        manager.add(args.package, dev=args.dev)

    elif args.command == "remove":
        manager.remove(args.package)

    elif args.command == "verify":
        ok = manager.verify()
        return 0 if ok else 1

    elif args.command == "audit":
        manager.audit()

    elif args.command == "export":
        output = manager.export()
        if output:
            print(output)
        else:
            logger.error("No lock file to export. Run 'lock' first.")
            return 1

    elif args.command == "status":
        manager.status()

    elif args.command == "docs":
        print_best_practices()

    else:
        parser.print_help()
        return 1

    return 0


if __name__ == "__main__":
    sys.exit(main())